{
  "mode": "method",
  "tests": [
    {
      "name": "initial_review_submission",
      "input": {
        "reviewer_id": "reviewer123",
        "submission_id": "submission456",
        "scores": [5, 4, 3],
        "comments": "Good work!"
      },
      "output": {
        "status": "success",
        "message": "Review submitted successfully."
      },
      "notes": "Validates that a review can be submitted initially."
    },
    {
      "name": "reopen_review_and_submit",
      "input": {
        "reviewer_id": "reviewer123",
        "submission_id": "submission456",
        "action": "reopen"
      },
      "output": {
        "scores": [5, 4, 3],
        "comments": "Good work!"
      },
      "notes": "Checks that previously entered scores and comments are displayed when reopening."
    },
    {
      "name": "submit_review_after_reopen",
      "input": {
        "reviewer_id": "reviewer123",
        "submission_id": "submission456",
        "action": "submit"
      },
      "output": {
        "status": "error",
        "message": "Cannot submit review with existing scores."
      },
      "notes": "Ensures that submission fails if scores are still displayed."
    },
    {
      "name": "multiple_reopen_attempts",
      "input": {
        "reviewer_id": "reviewer123",
        "submission_id": "submission456",
        "action": "reopen"
      },
      "output": {
        "scores": [5, 4, 3],
        "comments": "Good work!"
      },
      "notes": "Tests reopening multiple times to confirm consistent behavior."
    },
    {
      "name": "empty_scorecard_submission",
      "input": {
        "reviewer_id": "reviewer123",
        "submission_id": "submission456",
        "scores": [],
        "comments": ""
      },
      "output": {
        "status": "error",
        "message": "Scorecard cannot be empty."
      },
      "notes": "Validates that an empty scorecard cannot be submitted."
    },
    {
      "name": "invalid_reviewer_id",
      "input": {
        "reviewer_id": "invalid_reviewer",
        "submission_id": "submission456",
        "action": "reopen"
      },
      "output": {
        "status": "error",
        "message": "Reviewer ID not found."
      },
      "notes": "Tests behavior with an invalid reviewer ID."
    },
    {
      "name": "nonexistent_submission_id",
      "input": {
        "reviewer_id": "reviewer123",
        "submission_id": "nonexistent_submission",
        "action": "reopen"
      },
      "output": {
        "status": "error",
        "message": "Submission ID not found."
      },
      "notes": "Checks response when trying to reopen a nonexistent submission."
    },
    {
      "name": "submit_after_editing_scores",
      "input": {
        "reviewer_id": "reviewer123",
        "submission_id": "submission456",
        "scores": [4, 5, 3],
        "comments": "Updated review."
      },
      "output": {
        "status": "success",
        "message": "Review submitted successfully."
      },
      "notes": "Validates that scores can be updated and submitted after reopening."
    }
  ],
  "assumptions": "The reviewer must have permission to review the submission.",
  "notes": "Ensure that the review process adheres to the expected workflow."
}
